// Extract recipient details from each row
const items = $input.all();

return items.map(item => {
  const row = item.json;

  // Customize these field names to match your sheet columns
  const name = row['Name'] || row['name'] || '';
  const company = row['Company'] || row['Company Name'] || row['company'] || '';
  const email = row['Email'] || row['email'] || '';
  const rowNumber = row['row_number'] || row['__ROW_NUMBER__'] || '';

  if (!email || !name) {
    return { json: { skip: true, reason: 'Missing name or email', raw: row } };
  }

  // Personalized subject line
  const subject = `Exploring Opportunities at ${company} – [Your Name]`;

  // Personalized email body (HTML)
  const emailBody = `
<html>
<body style="font-family: Arial, sans-serif; font-size: 14px; color: #333; line-height: 1.6;">
  <p>Dear ${name},</p>

  <p>
    I hope this message finds you well. I came across <strong>${company}</strong> and was genuinely impressed 
    by the work your team is doing. I'm reaching out to express my interest in potential opportunities 
    where I could contribute meaningfully.
  </p>

  <p>
    I'm a <strong>[Your Role/Title]</strong> with experience in <strong>[Your Key Skills]</strong>. 
    I believe my background aligns well with the kind of work ${company} is focused on, 
    and I'd love the opportunity to connect and explore how I might add value to your team.
  </p>

  <p>
    I've attached my resume for your reference. I'd be happy to schedule a brief call 
    at your convenience — even 15 minutes would be wonderful.
  </p>

  <p>
    Thank you so much for your time, ${name}. I look forward to the possibility of connecting!
  </p>

  <p>
    Warm regards,<br/>
    <strong>[Your Full Name]</strong><br/>
    [Your Phone Number]<br/>
    [Your LinkedIn URL]<br/>
    [Your Portfolio/Website]
  </p>
</body>
</html>`;

  return {
    json: {
      skip: false,
      name,
      company,
      email,
      subject,
      emailBody,
      rowNumber
    }
  };
});

// Log errors without stopping the workflow
const error = $input.first().json;
console.error('Email send failed:', JSON.stringify(error));

return [{
  json: {
    status: 'failed',
    timestamp: new Date().toISOString(),
    error: error
  }
}];
